import{_ as a,o as i,c as l,ah as o}from"./chunks/framework.Bi9enVNS.js";const u=JSON.parse('{"title":"常见工作流","description":"","frontmatter":{},"headers":[],"relativePath":"guide/workflows.md","filePath":"guide/workflows.md","lastUpdated":1774205896000}'),s={name:"guide/workflows.md"};function t(d,e,c,n,r,p){return i(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="常见工作流" tabindex="-1">常见工作流 <a class="header-anchor" href="#常见工作流" aria-label="Permalink to &quot;常见工作流&quot;">​</a></h1><p>这一页把当前参考实现最常见的使用路径拆成 5 个连续步骤。</p><h2 id="_1-灌入示例日志" tabindex="-1">1. 灌入示例日志 <a class="header-anchor" href="#_1-灌入示例日志" aria-label="Permalink to &quot;1. 灌入示例日志&quot;">​</a></h2><p>先用 sender 或示例文件把一批日志送进服务：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./cmd/vlt-sender</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -environment</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> json</span></span></code></pre></div><p>如果你想演示不同拓扑形态，优先使用这 4 个示例文件：</p><ul><li><code>examples/upload.json</code></li><li><code>examples/upload-fanout.json</code></li><li><code>examples/upload-retry-loop.json</code></li><li><code>examples/upload-bus-handoff.json</code></li></ul><h2 id="_2-搜索日志" tabindex="-1">2. 搜索日志 <a class="header-anchor" href="#_2-搜索日志" aria-label="Permalink to &quot;2. 搜索日志&quot;">​</a></h2><p>日志搜索入口是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /v1/logs/search</span></span></code></pre></div><p>你可以组合以下筛选参数：</p><ul><li><code>project</code></li><li><code>environment</code></li><li><code>source_type</code></li><li><code>source_name</code></li><li><code>severity_number</code></li><li><code>trace_id</code></li><li><code>keyword</code></li><li><code>start</code></li><li><code>end</code></li></ul><p>典型用法：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://localhost:8080/v1/logs/search?project=demo&amp;trace_id=0123456789abcdef0123456789abcdef&quot;</span></span></code></pre></div><h2 id="_3-打开一条-trace" tabindex="-1">3. 打开一条 Trace <a class="header-anchor" href="#_3-打开一条-trace" aria-label="Permalink to &quot;3. 打开一条 Trace&quot;">​</a></h2><p>一旦你从日志列表拿到 <code>trace_id</code>，就可以继续读取：</p><ul><li><code>GET /v1/traces/{trace_id}</code></li><li><code>GET /v1/traces/{trace_id}/timeline</code></li><li><code>GET /v1/traces/{trace_id}/topology</code></li></ul><p>前端的 Logs Explorer 也是通过日志行上的 <code>trace_id</code> 进入 Trace Workbench。</p><h2 id="_4-查看-timeline-topology" tabindex="-1">4. 查看 Timeline / Topology <a class="header-anchor" href="#_4-查看-timeline-topology" aria-label="Permalink to &quot;4. 查看 Timeline / Topology&quot;">​</a></h2><h3 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">​</a></h3><ul><li>每条 lane 对应一个 <code>source_fingerprint</code></li><li>每个 lane 会带上事件列表、错误数、首次/最后出现时间</li><li>lane 顺序按 <code>first_seen</code> 排序</li></ul><h3 id="topology" tabindex="-1">Topology <a class="header-anchor" href="#topology" aria-label="Permalink to &quot;Topology&quot;">​</a></h3><ul><li>节点按 <code>source_fingerprint</code> 聚合</li><li>边由 Trace 内相邻来源段推导</li><li>连续相同来源会先折叠，再生成边</li><li>错误数判定基于 <code>severity_number &gt;= 17</code></li></ul><h2 id="_5-浏览-sources" tabindex="-1">5. 浏览 Sources <a class="header-anchor" href="#_5-浏览-sources" aria-label="Permalink to &quot;5. 浏览 Sources&quot;">​</a></h2><p>来源视图适合回答“当前项目/环境里有哪些来源实例”：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /v1/sources</span></span></code></pre></div><p>返回结构是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source_type -&gt; source_name -&gt; instance_id</span></span></code></pre></div><p>如果某条记录没有 <code>instance_id</code>，当前实现会在来源树里显示为 <code>-</code>。</p><h2 id="一条完整的推荐路径" tabindex="-1">一条完整的推荐路径 <a class="header-anchor" href="#一条完整的推荐路径" aria-label="Permalink to &quot;一条完整的推荐路径&quot;">​</a></h2><ol><li>启动后端</li><li>发送一个示例 JSON</li><li>通过 <code>GET /v1/logs/search</code> 确认写入成功</li><li>选中 <code>trace_id</code></li><li>打开 Timeline / Topology</li><li>用 Sources 视图检查来源分布</li></ol><h2 id="事实来源" tabindex="-1">事实来源 <a class="header-anchor" href="#事实来源" aria-label="Permalink to &quot;事实来源&quot;">​</a></h2><ul><li><code>internal/api/http.go</code></li><li><code>internal/store/store.go</code></li><li><code>internal/store/memory/memory.go</code></li><li><code>web/src/App.jsx</code></li></ul>',33)])])}const k=a(s,[["render",t]]);export{u as __pageData,k as default};
